import numpy as np
from numpy.random import rand
from firedrake import *

class Base_CHNS_sur(object):
    def __init__(self, mesh, paras):
        super().__init__()
        self.mesh = mesh
        self.X = SpatialCoordinate(self.mesh) # X[0] = x, X[1] = y, ...
        self.t = Constant(0.0)

        self.excpt_key = ["polydegree","seed"]

        for key, value in paras.items():
            if key in self.excpt_key:
                setattr(self, key, value)
            else:
                setattr(self, key, Constant(value))

    def func(self, phi):
        return (phi ** 3 - phi)

    def func_g(pde, rho):
        g1 = ln(rho / pde.sigma) + 1 - (1 - rho) / pde.sigma
        g2 = ln(rho / (1 - rho))
        g3 = ln(pde.sigma / (1 - rho)) - 1 + rho / pde.sigma
        return conditional(
            ge(rho, 1 - pde.sigma),
            g1,
            conditional(
                le(rho, pde.sigma),
                g3,
                g2
            )
        )

    def cal_mu(self, phi, rho):
        return -self.gamma_1 * div(grad(phi)) - self.xi * div(grad(phi) * dot(grad(phi),grad(phi))) + (1 / self.epsilon ** 2) * self.func(phi) + self.theta * div(rho * grad(phi)) + self.alpha_1 * rho * phi - self.alpha_2 * rho

    def cal_omega(self, phi, rho):
        return -self.gamma_2 * div(grad(rho)) + (1 / self.eta ** 2) * self.func_g(rho) - (self.theta / 2) * dot(grad(phi), grad(phi)) + (self.alpha_1 / 2) * phi ** 2 - self.alpha_2 * phi - self.beta * rho

class pde_CHNS_sur_data(Base_CHNS_sur):
    """
    Periodic bc, Omega = [0,2*pi] * [0,4*pi]
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_data"

        self.exact_phi = sin(self.X[0])*cos(self.t)*cos(self.X[1])
        self.exact_rho = (0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t)
        self.exact_mu = self.cal_mu(self.exact_phi, self.exact_rho)
        self.exact_omega = self.cal_omega(self.exact_phi, self.exact_rho)
        self.exact_u = as_vector([
            sin(self.X[1])*cos(self.t)*cos(self.X[0]),
            -sin(self.X[0])*cos(self.t)*cos(self.X[1])
        ])
        self.exact_p = sin(self.t)*sin(self.X[0])*sin(self.X[1])
        self.exact_lambda = Constant(1.0)
        self.exact_zeta = Constant(1.0)

        self.init_phi = self.exact_phi
        self.init_mu = self.exact_mu
        self.init_rho = self.exact_rho
        self.init_omega = self.exact_omega
        self.init_u = self.exact_u
