        f1 = (-2*self.Re*self.epsilon**2*self.eta**2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1)*sin(self.X[0])*cos(self.t) + self.Re*self.epsilon**2*(self.eta**2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1)*(0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*(2*self.alpha_1*sin(self.X[0])*cos(self.t)*cos(self.X[1])**2 - 2*self.alpha_2*cos(self.X[1]) - 0.2*self.beta*cos(self.X[1]) + 0.4*self.gamma_2*cos(self.X[1]) + 2*self.theta*sin(self.X[0])*cos(self.t)*cos(2*self.X[1]))*cos(self.t) + 0.2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1)*cos(self.X[1]) - 0.2*(0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t)*cos(self.X[1])) + 2*self.Re*self.eta**2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1)*(self.epsilon**2*(self.alpha_1*(0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t)*cos(self.X[1]) + 0.1*self.alpha_1*sin(self.X[0])*cos(self.t)*cos(self.X[1])**2 - 0.1*self.alpha_2*cos(self.X[1]) + 2*self.gamma_1*cos(self.X[1]) - self.theta*(-0.8*sin(self.X[0])*sin(self.X[1])**2 + 0.6*sin(self.X[0]) + 1.0*cos(self.X[1]))*cos(self.t) + 2*self.xi*(18*sin(self.X[0])**2*sin(self.X[1])**2 - 6*sin(self.X[0])**2 - 4*sin(self.X[1])**2 + 2)*cos(self.t)**2*cos(self.X[1])) + 3*sin(self.X[0])**2*cos(self.t)**2*cos(self.X[1])**3 - cos(self.X[1]))*sin(self.X[0])*cos(self.t)*cos(self.X[1]) + 4*self.epsilon**2*self.eta**2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1)*sin(self.X[1]))*cos(self.t)*cos(self.X[0])/(2*self.Re*self.epsilon**2*self.eta**2*((0.1*sin(self.X[0])*cos(self.X[1]) + 0.5)*cos(self.t) - 1))
