class pde_CHNS_sur_data_energy(pde_CHNS_sur_data):
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_data_energy"
        self.rhs_phi = Constant(0.0)
        self.rhs_rho = Constant(0.0)
        self.rhs_ns = as_vector([0,0])


