class pde_CHNS_sur_spinodal_decomposition_1(Base_CHNS_sur):
    """
    05spinodal_decomposition/ex05_1
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_spinodal_decomposition_1"

        np.random.seed(self.seed)
        V = FunctionSpace(self.mesh,"CG",self.polydegree)
        phi, rho = Function(V), Function(V)
        data = phi.dat.data
        data[:] = self.phibar + self.phi_amplitude * (2 * rand(*data.shape) - 1)
        data = rho.dat.data
        data[:] = self.rhobar + self.rho_amplitude * (2 * rand(*data.shape) - 1)

        self.init_phi = phi
        self.init_rho = rho
        self.init_mu = self.cal_mu(phi, rho)
        self.init_omega = self.cal_omega(phi, rho)
        self.init_u = as_vector([0,0])
        self.init_p = Constant(0)

        self.rhs_phi = None
        self.rhs_rho = None
        self.rhs_ns = None

class pde_CHNS_sur_spinodal_decomposition_2(pde_CHNS_sur_spinodal_decomposition_1):
    """
    05spinodal_decomposition/ex05_2
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_spinodal_decomposition_2"

