class pde_CHNS_sur_droplets_1(Base_CHNS_sur):
    """
    04droplets/ex04_1
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_droplets_1"

        rl = [0.36*pi, 0.1*pi, 0.1*pi]
        xl = [pi, 1.5*pi, 0.5*pi]
        yl = [pi, pi, pi]
        self.init_phi = (tanh((rl[0] - sqrt((self.X[0] - xl[0]) ** 2 + (self.X[1] - yl[0]) ** 2)) / (sqrt(2) * self.epsilon))
                         + tanh((rl[1] - sqrt((self.X[0] - xl[1]) ** 2 + (self.X[1] - yl[1]) ** 2)) / (sqrt(2) * self.epsilon))
                         + tanh((rl[2] - sqrt((self.X[0] - xl[2]) ** 2 + (self.X[1] - yl[2]) ** 2)) / (sqrt(2) * self.epsilon)) + 2)

        V = FunctionSpace(self.mesh,"CG",self.polydegree)
        rho = Function(V)
        rho.interpolate(Constant(0.2))
        self.init_rho = rho
        self.init_mu = self.cal_mu(self.init_phi, self.init_rho)
        self.init_omega = self.cal_omega(self.init_phi, self.init_rho)
        self.init_u = as_vector([0,0])
        self.init_p = Constant(0)

        self.rhs_phi = None
        self.rhs_rho = None
        self.rhs_ns = None

class pde_CHNS_sur_droplets_2(Base_CHNS_sur):
    """
    04droplets/ex04_2
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_droplets_2"

        rl = [0.4*pi, 0.4*pi, 0.4*pi]
        xl = [0.58*pi, 1.42*pi, pi]
        yl = [0.65*pi, 0.65*pi, 1.37 * pi]
        self.init_phi = (tanh((rl[0] - sqrt((self.X[0] - xl[0]) ** 2 + (self.X[1] - yl[0]) ** 2)) / (sqrt(2) * self.epsilon))
                         + tanh((rl[1] - sqrt((self.X[0] - xl[1]) ** 2 + (self.X[1] - yl[1]) ** 2)) / (sqrt(2) * self.epsilon))
                         + tanh((rl[2] - sqrt((self.X[0] - xl[2]) ** 2 + (self.X[1] - yl[2]) ** 2)) / (sqrt(2) * self.epsilon)) + 2)

        np.random.seed(self.seed)
        V = FunctionSpace(self.mesh,"CG",self.polydegree)
        rho = Function(V)
        data = rho.dat.data
        data[:] = self.rhobar + self.rho_amplitude * (2 * np.random.rand(*data.shape) - 1)
        self.init_rho = rho

        self.init_mu = self.cal_mu(self.init_phi, self.init_rho)
        self.init_omega = self.cal_omega(self.init_phi, self.init_rho)
        self.init_u = as_vector([0,0])
        self.init_p = Constant(0)

        self.rhs_phi = None
        self.rhs_rho = None
        self.rhs_ns = None

class pde_CHNS_sur_shearflow_1(Base_CHNS_sur):
    """
    shearflow_1
    """
    def __init__(self, mesh, paras):
        super().__init__(mesh, paras)
        self.name = "pde_CHNS_sur_shearflow_1"

        self.init_phi = 1 + (tanh((0.28 - sqrt((self.X[0] - 0.8) ** 2 + (self.X[1] - 1.29) ** 2)) / self.epsilon) + tanh((0.28 - sqrt((self.X[0] - 1.2) ** 2 + (self.X[1] - 0.71) ** 2)) / self.epsilon))
        self.init_rho = Constant(0.2) * (self.X[0] - self.X[0] + 1)
        self.init_mu = self.cal_mu(self.init_phi, self.init_rho)
        self.init_omega = self.cal_omega(self.init_phi, self.init_rho)
        self.init_u = as_vector([10 * (self.X[1] - 1), 0])
        self.init_p = Constant(0)
        self.bc_u_right = as_vector([10, 0])# actually is up, because in periodic x-mesh, id-2 means up
        self.bc_u_left = as_vector([-10, 0])# actually is down, because in periodic x-mesh, id-1 means down

        self.rhs_phi = None
        self.rhs_rho = None
        self.rhs_ns = None

